import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });

const tools = [
  {
    name: 'vector_search',
    description: 'Search vector database',
    inputSchema: {
      type: 'object',
      properties: {
        query: { type: 'string' },
        top_k: { type: 'integer', default: 5 }
      }
    }
  }
];

// Usage in agent loop
const stream = await client.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools,
  messages: [{ role: 'user', content: 'What is Agentic RAG?' }]
});

def format_cited_response(content: str, sources: list):
    cited_content = content
    for i, source in enumerate(sources):
        cited_content += f"\n[{i+1}] {source['title']} - {source['chunk'][:200]}..."
    return {
        'response': content,
        'citations': sources,
        'source_count': len(sources)
    }

